                    Tx_x += basisX[a]*xControlPointCoordinates[a]; 
                    Tx_y += basisY[a]*xControlPointCoordinates[a]; 
                    Tx_z += basisZ[a]*xControlPointCoordinates[a]; 

                    Ty_x += basisX[a]*yControlPointCoordinates[a]; 
