							(field->Ex[i][j][k + 1] - field->Ex[i][j][k]) * invdz - Ms[i][j][k]); 

						MjuZ = 0.5 * (Mju[i][j][k] + Mju[i][j][k - 1]) * MU_Z; 
						SigSZ = 0.5 * (SigS[i][j][k] + SigS[i][j][k - 1]); 
						dtMju = dt / MjuZ; 
