    auto old_start = adapter.b(); 
    auto old_end = adapter.e(); 
    auto old_rc_start = adapter.rb(); 
    auto old_rc_end = adapter.re(); 
    uint64_t new_start, new_end, new_rc_start, new_rc_end; 

