for (i=0; i<nbodies; i++) { 
		rmin = 100.0; 
		fx   = 0.0; 
		fy   = 0.0; 
		fz   = 0.0; 
		for (j=0; j<nbodies; j++) { 
			if(i==j) 
				continue; 
			rx = bodies[i].x - bodies[j].x; 
			ry = bodies[i].y - bodies[j].y; 
			rz = bodies[i].z - bodies[j].z; 
			r  = rx*rx + ry*ry + rz*rz; 

			if (r < rmin) 
				rmin = r; 
			r  = r * sqrt(r); 
			fx -= bodies[j].mass * rx / r; 
			fy -= bodies[j].mass * ry / r; 
			fz -= bodies[j].mass * rz / r; 
		} 
		bodies[i].fx += fx; 
		bodies[i].fy += fy; 
		bodies[i].fz += fz; 
		fx = sqrt(fx*fx + fy*fy + fz*fz)/rmin; 
		if (fx > max_f) 
			max_f = fx; 
	}

