        dd1 += Fgi * w3 * 2 + Fhi1 * w + ww1 * Fi; 

        vec_type3 FgXXY(Fgi.x(), Fgi.x(), Fgi.y()); 
        vec_type3 w3YZZ(w3.y(), w3.z(), w3.z()); 
        vec_type3 FgiYZZ(Fgi.y(), Fgi.z(), Fgi.z()); 
        vec_type3 w3XXY(w3.x(), w3.x(), w3.y()); 
        dd2 += FgXXY * w3YZZ + FgiYZZ * w3XXY + Fhi2 * w + ww2 * Fi; 
      } 

