float eucliDist(float *rec1, float *rec2, int m)
{
  float sum = 0.0;
  for (int i = 0; i < m; i++)
  {
    sum += (rec1[i] - rec2[i]) * (rec1[i] - rec2[i]);
  }

  return sqrt(sum);
}

