double calc_dist(double *array1, double *array2)
{
  double dist = 0.0;
  double tmp = 0;
  for (int i = 0; i < 30; ++i)
  {
    tmp = array1[i] - array2[i];
    dist += tmp * tmp;
  }

  return dist;
}


