        for (int j = i + 1; j < N; ++j) { 
            Eigen::Vector3d dr = r_vectors.row(j) - r_vectors.row(i); 
            for (int k = 0; k < 3; ++k){ 
                if (L[k] > 0) 
                    dr[k] -= int(dr[k] / L[k] + 
                                 0.5 * (int(dr[k] > 0) - int(dr[k] < 0))) * 
                             L[k]; 
            } 
            double r_norm = dr.norm(); 
            double f0 = 
                r_norm > 2 * a 
                    ? -((eps / b) * exp(-(r_norm - 2.0 * a) / b) / r_norm) 
                    : -((eps / b) / std::max(r_norm, 1e-25)); 

            for (int k = 0; k < 3; ++k) 
                force[i * 3 + k] += f0 * dr[k]; 
            for (int k = 0; k < 3; ++k) 
                force[j * 3 + k] -= f0 * dr[k]; 
        } 
    }

