int inBounds(double x, double y)
{
  if ((((x > 1) || (y > 1)) || (y < 0)) || (x < 0))
    return 0;

  double distance = sqrt(((x - .5) * (x - .5)) + ((y - .5) * (y - .5)));
  return (distance <= .5) ? (1) : (0);
}

