int circumscribed(int radius)
{
  float xcoord = ((double) rand()) / 32767;
  float ycoord = ((double) rand()) / 32767;
  float coord = (xcoord * xcoord) + (ycoord * ycoord);
  return (coord <= radius) ? (1) : (-1);
}

