        if (m_rhd[i] > 1)    

            actualVaporPressure = m_rhd[i] * satVaporPressure * 0.01f; 
        else 
            actualVaporPressure = m_rhd[i] * satVaporPressure; 
        m_vpd[i] = satVaporPressure - actualVaporPressure; 
        float rbo = -(0.34f - 0.139f * sqrt(actualVaporPressure)); 


