            rto = 0.9f * (m_sr[i] / m_srMax) + 0.1f; 


        float tk = m_tMean[i] + 273.15f; 
        float raLongWave = rbo * rto * 4.9e-9f * pow(tk, 4.f); 

        float raNet = raShortWave + raLongWave; 





