            std::cout << tmp.template cast<double>().transpose() << std::endl; 
            std::cout << tmp.maxCoeff() << std::endl; 
            std::cout << bins.at(k) << std::endl; 
            throw std::runtime_error("probability vector not in [0, 1]"); 
