            b_mid.fill(b(y_mid-1)); 

            const double lhs = k * b(y_mid-1) + arma::accu(small_C % arma::min(b_mid,b)); 


            if (lhs == a(x)) { 
                y_low = y_mid; 
                y_up = y_mid; 
            } else if (lhs > a(x)) { 
                y_up = y_mid; 
            } else { 
                y_low = y_mid + 1; 
            } 
        } 


        if ((y_low==1) && ( k * b(y_low-1) + arma::accu(small_C % arma::min(b_low,b)) >= a(x) )) { 
            vals(x) = a(x) / (k + small_C_sum); 
