            arma::vec b_up(nb_Y); 
            b_up.fill(b(y_up-1)); 

            if ((y_up==nb_Y) && ( k * b(y_up-1) + arma::accu(small_C % arma::min(b_up,b)) <= a(x) )) { 
                vals(x) = (a(x) - arma::accu(small_C % b)) / k ;             
            } else { 
                int y_incl = y_low - 1; 

                const arma::vec temp_vec = small_C % b; 
                const double term_1 = a(x) - arma::accu(temp_vec.rows(0,y_incl)); 
