      } 
      else 
      { 
        int clipped = 0; 



        float R = 0.0f, Gmin = FLT_MAX, Gmax = -FLT_MAX, B = 0.0f; 
        for(int jj = 0; jj <= 1; jj++) 
        { 
          for(int ii = 0; ii <= 1; ii++) 
          { 
